//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: **pPr / rPr child element ordering and schema validity (Annex A)**
//!
//! Each `#[test]` encodes a Word-consumption / schema-validity constraint mined
//! from ECMA-376 / ISO 29500 Annex A (the `CT_RPr` / `CT_PPrBase` /
//! `EG_RPrBase` sequences).
//!
//! CONTRACT (oracle-adjudicated, see
//! stemma-engine/docs/spec-compliance/CONFORMANCE-SWEEP-SUMMARY.md): real Word
//! TOLERATES rPr/pPr child-order variance and text-first rPr on open — it does
//! NOT repair them and does NOT normalize order on save. stemma re-zips
//! untouched body markup BYTE-FOR-BYTE (the serializer's Annex-A ordering only
//! runs on edited/rebuilt blocks), so on the no-edit roundtrip the authored
//! order is preserved verbatim. That preservation is the CORRECT contract, not a
//! gap. These tests therefore assert (a) the authored order survives the no-edit
//! roundtrip unchanged and (b) `validate()` reports opens-clean. Asserting that
//! the serializer reorders untouched markup would be a wrong-path test-bug (it
//! would only ever pass on an edit that rebuilds the block).

use std::io::{Read, Write};

use stemma::ExportOptions;
use stemma::api::Document;
use zip::write::FileOptions;

// ─── Prelude: zip plumbing (mirrors the shared spec-suite prelude
//     and tests/common/mod.rs) ──────────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is the inner content of
/// `<w:body>` (paragraphs + a trailing `<w:sectPr/>`). `extra_parts` are
/// additional package parts (e.g. `word/styles.xml`); each gets a
/// `[Content_Types].xml` override.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#,
    );

    // Build content-type overrides for any extra parts.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part, _) in extra_parts {
        let content_type = match *part {
            "word/styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "word/numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!("make_docx: unknown extra part content-type for {other}"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{part}" ContentType="{content_type}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // Relationship from document.xml to any extra parts (styles/numbering).
    let mut doc_rels = String::from(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">"#,
    );
    for (rid, (part, _)) in (1..).zip(extra_parts.iter()) {
        let rel_type = match *part {
            "word/styles.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles"
            }
            "word/numbering.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering"
            }
            other => panic!("make_docx: unknown extra part rel-type for {other}"),
        };
        let target = part.strip_prefix("word/").unwrap_or(part);
        doc_rels.push_str(&format!(
            r#"<Relationship Id="rIdExtra{rid}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }
    doc_rels.push_str("</Relationships>");

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive =
        zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip archive");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml in archive");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse with stemma, re-serialize, and return the resulting `word/document.xml`.
/// Ordering expectations assert on this string because element ordering is
/// markup the serializer actively produces (Annex A sequence).
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse docx");
    let out = doc
        .serialize(&ExportOptions::default())
        .expect("serialize docx");
    document_xml_of(&out)
}

/// Assert that `haystack` contains all `needles` in the given order (each
/// successive needle found at or after the end of the previous match). This is
/// the no-`regex`-crate translation of the spec's "A before B before C"
/// ordering regexes: every regex in this area is an ordered-adjacency pattern
/// with `\s*` / `.*` between literal element tags, which an in-order
/// substring search faithfully captures.
fn contains_in_order(haystack: &str, needles: &[&str]) -> bool {
    let mut cursor = 0usize;
    for needle in needles {
        match haystack[cursor..].find(needle) {
            Some(rel) => cursor += rel + needle.len(),
            None => return false,
        }
    }
    true
}

/// opensClean helper: stemma's package validator reports no errors.
fn opens_clean(bytes: &[u8], ctx: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok,
        "{ctx} — expected opens-clean (schema-valid), but validate() reported issues: {:?}",
        report.issues
    );
}

