#[test]
fn rpr_authored_u_before_sz_preserved_verbatim_and_opens_clean() {
    // Authored u-first, sz-second. Annex A's canonical sequence is sz (pos 24)
    // before u (pos 40), but Word tolerates the variance on open and stemma
    // re-zips this untouched run verbatim — so the authored order survives and
    // the package opens clean. (Reordering would only happen on an edit path.)
    let body = r#"<w:p><w:r><w:rPr><w:u w:val="single"/><w:sz w:val="24"/></w:rPr><w:t>x</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        contains_in_order(&xml, &["<w:u", "/>", "<w:sz", "/>"]),
        "untouched run markup round-trips verbatim: authored u-then-sz order is preserved on the no-edit roundtrip (Word tolerates the order variance per the oracle adjudication). XML: {xml}"
    );
    opens_clean(
        &b,
        "rpr_authored_u_before_sz_preserved_verbatim_and_opens_clean: Word tolerates rPr order variance, so this round-trips schema-valid (Annex A CT_RPr)",
    );
}

