    let body = r#"<w:p><w:r><w:rPr><w:vertAlign w:val="superscript"/><w:u w:val="single"/></w:rPr><w:t>x</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
