    let body = r#"<w:p><w:pPr><w:pageBreakBefore/><w:keepLines/><w:keepNext/></w:pPr><w:r><w:t>x</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
